export declare const editorStyles = "\n  .ProseMirror {\n    min-height: 200px;\n  }\n  \n  .ProseMirror > * + * {\n    margin-top: 0.75em;\n  }\n\n  .ProseMirror h1 {\n    font-size: 2.5rem;\n    font-weight: 700;\n    line-height: 1.2;\n    margin-bottom: 0.5em;\n    color: var(--color-primary-text);\n  }\n\n  .ProseMirror h2 {\n    font-size: 1.875rem;\n    font-weight: 600;\n    line-height: 1.3;\n    margin-top: 1.5em;\n    color: var(--color-primary-text);\n  }\n\n  .ProseMirror h3 {\n    font-size: 1.5rem;\n    font-weight: 600;\n    line-height: 1.4;\n    margin-top: 1.5em;\n    color: var(--color-primary-text);\n  }\n\n  .ProseMirror p {\n    font-size: 1rem;\n    line-height: 1.75;\n    color: var(--color-secondary-text);\n  }\n\n  .ProseMirror ul,\n  .ProseMirror ol {\n    padding-left: 1.5rem;\n    color: var(--color-secondary-text);\n  }\n\n  .ProseMirror ul li {\n    list-style-type: disc;\n    padding-left: 0.25rem;\n  }\n\n  .ProseMirror ol li {\n    list-style-type: decimal;\n    padding-left: 0.25rem;\n  }\n\n  .ProseMirror li {\n    margin-top: 0.5em;\n    line-height: 1.75;\n  }\n\n  .ProseMirror blockquote {\n    border-left: 2px solid var(--color-stroke);\n    padding-left: 1rem;\n    font-style: italic;\n    color: var(--color-primary-text);\n    margin: 1.5em 0;\n  }\n\n  .ProseMirror code {\n    color: var(--color-secondary-text);\n    padding: 0.2em 0.4em;\n    border-radius: 0.25rem;\n    font-size: 0.875em;\n  }\n\n  .ProseMirror pre {\n    background-color: rgba(31, 41, 55, 0.3);\n    color: var(--color-secondary-text);\n    padding: 1rem;\n    border-radius: 0.5rem;\n    overflow-x: auto;\n    \n    font-size: 0.875rem;\n    line-height: 1.5;\n    margin: 1.5em 0;\n  }\n\n  .ProseMirror pre code {\n    background: none;\n    color: inherit;\n    padding: 0;\n    font-size: inherit;\n  }\n\n  .ProseMirror hr {\n    border: none;\n    border-top: 2px solid var(--color-border);\n    margin: 2rem 0;\n  }\n\n  .ProseMirror img {\n    max-width: 100%;\n    height: auto;\n    border-radius: 0.5rem;\n    margin: 1em 0;\n  }\n\n  .ProseMirror img[style*=\"text-align: center\"] {\n    display: block;\n    margin-left: auto;\n    margin-right: auto;\n  }\n\n  .ProseMirror img[style*=\"text-align: right\"] {\n    display: block;\n    margin-left: auto;\n    margin-right: 0;\n  }\n\n  .ProseMirror mark {\n    background-color: #fef3c7;\n    padding: 0.125em 0.25em;\n    border-radius: 0.125rem;\n  }\n\n  .ProseMirror p.is-editor-empty:first-child::before {\n    color: var(--disabled-text);\n    content: attr(data-placeholder);\n    float: left;\n    height: 0;\n    pointer-events: none;\n  }\n\n  .ProseMirror h1.is-empty::before,\n  .ProseMirror h2.is-empty::before,\n  .ProseMirror h3.is-empty::before {\n    color: #adb5bd;\n    content: attr(data-placeholder);\n    float: left;\n    height: 0;\n    pointer-events: none;\n  }\n\n  .ProseMirror:focus {\n    outline: none;\n  }\n\n  .ProseMirror a {\n    color: #3b82f6;\n    text-decoration: underline;\n    cursor: pointer;\n  }\n\n  .ProseMirror a:hover {\n    color: #2563eb;\n  }\n    \n.prose h1 a,\n.prose h2 a,\n.prose h3 a,\n.prose h4 a,\n.prose h5 a,\n.prose h6 a {\n  color: inherit !important;\n  text-decoration: none !important;\n  font-weight: inherit !important;\n}\n\n  .ProseMirror .tableWrapper {\n    overflow-x: auto;\n    -webkit-overflow-scrolling: touch;\n    margin: 1.5em 0;\n  }\n\n  .ProseMirror table {\n    border-collapse: separate;\n    border-spacing: 0;\n    table-layout: fixed;\n    width: 100%;\n    overflow: hidden;\n    background-color: transparent;\n    border: 1px solid var(--button-fill-3);\n    border-radius: 0.75rem;\n  }\n\n  .ProseMirror td,\n  .ProseMirror th {\n    min-width: 1em;\n    border: 1px solid var(--button-fill-3);\n    padding: 0.5rem 0.75rem;\n    vertical-align: top;\n    text-align: center;\n    box-sizing: border-box;\n    position: relative;\n    word-break: break-word;\n    \n  }\n\n  .ProseMirror th {\n    font-weight: 600;\n    background-color: var(--button-fill-3);\n    color: var(--color-primary-text);\n    border: 1px solid var(--node-field-fill);\n  }\n\n  .ProseMirror td {\n    color: var(--color-secondary-text);\n  }\n\n  /* Rounded corners on outer cells */\n  .ProseMirror table tr:first-child th:first-child,\n  .ProseMirror table tr:first-child td:first-child {\n    border-top-left-radius: 0.75rem;\n  }\n\n  .ProseMirror table tr:first-child th:last-child,\n  .ProseMirror table tr:first-child td:last-child {\n    border-top-right-radius: 0.75rem;\n  }\n\n  .ProseMirror table tr:last-child td:first-child,\n  .ProseMirror table tr:last-child th:first-child {\n    border-bottom-left-radius: 0.75rem;\n  }\n\n  .ProseMirror table tr:last-child td:last-child,\n  .ProseMirror table tr:last-child th:last-child {\n    border-bottom-right-radius: 0.75rem;\n  }\n\n  .ProseMirror .selectedCell::after {\n    z-index: 2;\n    position: absolute;\n    content: \"\";\n    left: 0;\n    right: 0;\n    top: 0;\n    bottom: 0;\n    background: rgba(59, 130, 246, 0.15);\n    pointer-events: none;\n  }\n\n  .ProseMirror .column-resize-handle {\n    position: absolute;\n    right: -2px;\n    top: 0;\n    bottom: 0;\n    width: 4px;\n    background-color: #3b82f6;\n    pointer-events: none;\n  }\n\n  .ProseMirror.resize-cursor {\n    cursor: col-resize;\n  }\n\n  .ProseMirror table > * + * {\n    margin-top: 0;\n  }\n  ";
